H,N = map(int,input().split())

A = [0]*N
B = [0]*N
for i in range(N):
    A[i],B[i] = map(int,input().split())

dp = [[10**10]*(H+1) for _ in range(N+1)]
dp[0][0] = 0
for i in range(1,N+1):
    for j in range(H+1):
        if j >= A[i-1]:
            dp[i][j] = min(dp[i-1][j],dp[i][j-A[i-1]]+B[i-1])
        else:
            dp[i][j] = dp[i-1][j]

print(dp[N][H])
